#!/usr/bin/env python3
"""SELF-CONTAINED Kaggle kernel — Rubik's-Cube Coding System speed benchmark.

One CA-opcode core -> all 18 language faces. No repo clone, no deps: the cube
emitter + 18 language dialects are inlined (base64 below). Measures emit
throughput on Kaggle free compute. Auto-generated from python/scbe/polyglot.py.
"""
import base64
import json
import multiprocessing
import platform
import random
import time

_DATA = json.loads(base64.b64decode("").decode("utf-8"))
DIALECTS = _DATA["dialects"]
OPS = _DATA["ops"]
BINOPS, CMPS = OPS["BINOPS"], OPS["CMPS"]
FUNC2, FUNC1 = set(OPS["FUNC2"]), set(OPS["FUNC1"])


def sub(t, **kw):
    for k, v in kw.items():
        t = t.replace("{" + k + "}", str(v))
    return t


def render(n, d):
    if n in BINOPS:
        return "a " + BINOPS[n] + " b", True
    if n in CMPS:
        return sub(d["cmp_tmpl"], cond="a " + CMPS[n] + " b"), True
    if n in FUNC2:
        return sub(d["func2"][n], a="a", b="b"), True
    return sub(d["func1"][n], a="a"), False


def emit(names, lang, fn="tongue_fn", args=("a", "b", "c")):
    d = DIALECTS[lang]
    ind = d["indent"]
    L = list(d["prelude"])
    L.append(sub(d["fn_open"], fn=fn, params=", ".join(args)))
    L.append(ind + sub(d["stack_init"], init=", ".join(args)))
    for n in names:
        expr, is_bin = render(n, d)
        pop = d["pop2"] if is_bin else d["pop1"]
        L.append(ind + pop + sub(d["push"], expr=expr) + "  " + d["comment"] + " " + n)
    L.append(ind + d["ret"])
    L.extend(d["fn_close"])
    L.append("")
    L.extend(sub(m, fn=fn) for m in d["main_tmpl"])
    return "\n".join(L) + "\n"


_BIN = list(set(BINOPS) | set(CMPS) | FUNC2)
_UN = list(FUNC1)


def rand_prog(length, rng):
    depth, ops = 3, []
    for _ in range(length):
        if depth >= 2 and (depth <= 1 or rng.random() < 0.6):
            ops.append(rng.choice(_BIN))
            depth -= 1
        else:
            ops.append(rng.choice(_UN))
        if depth < 1:
            depth = 1
    return ops


def bench(n, length, seed=7):
    rng = random.Random(seed)
    langs = sorted(DIALECTS)
    progs = [rand_prog(length, rng) for _ in range(n)]
    t0 = time.perf_counter()
    files = lines = chars = 0
    for p in progs:
        for lang in langs:
            s = emit(p, lang)
            files += 1
            lines += s.count("\n") + 1
            chars += len(s)
    dt = time.perf_counter() - t0
    return dict(languages=len(langs), programs=n, files=files, seconds=dt,
                programs_per_s=n / dt, files_per_s=files / dt,
                kloc_per_s=lines / 1000 / dt, mchars_per_s=chars / 1e6 / dt)


print("=" * 56)
print("RUBIK'S-CUBE CODING SYSTEM - KAGGLE SPEED BENCHMARK")
print("=" * 56)
print("node:", platform.platform(), "cores:", multiprocessing.cpu_count())
_ns = {}
exec(compile(emit(rand_prog(6, random.Random(7)), "python"), "b.py", "exec"), _ns)
print("correctness (python emit runs):", isinstance(_ns["tongue_fn"](2.0, 3.0, 4.0), (int, float)))
for _n, _L in [(5000, 12), (20000, 16)]:
    r = bench(_n, _L)
    print("\n--- {:,} programs x {} ops -> all {} languages ---".format(r["programs"], _L, r["languages"]))
    print("  {:>10,.0f}  programs/s".format(r["programs_per_s"]))
    print("  {:>10,.0f}  language-files/s".format(r["files_per_s"]))
    print("  {:>10,.1f}  KLOC/s".format(r["kloc_per_s"]))
    print("  {:>10,.2f}  M chars/s   ({:,} files in {:.2f}s)".format(r["mchars_per_s"], r["files"], r["seconds"]))
print("\nDONE")
